package dev.modichamiya.eclipse.gameplay.combat;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public final class CombatService {private final Map<UUID,Double>health=new ConcurrentHashMap<>();public void register(UUID entity,double maximum){if(maximum<=0||!Double.isFinite(maximum))throw new IllegalArgumentException();health.put(entity,maximum);}public DamageResult calculate(DamageRequest request){double additive=request.modifiers().getOrDefault("additive",0d),multiplicative=request.modifiers().getOrDefault("multiplicative",1d);double raw=(request.base()+request.scaling()+additive)*multiplicative;boolean critical=new SplittableRandom(request.seed()).nextDouble()<Math.max(0,Math.min(1,request.criticalChance()));if(critical)raw*=Math.max(1,request.criticalDamage());double mitigation=100d/(100d+Math.max(0,request.targetDefense()));double resistance=Math.max(0,Math.min(.95,request.resistance()));double amount=Math.max(0,raw*mitigation*(1-resistance));return new DamageResult(amount,critical,amount*request.modifiers().getOrDefault("threat",1d),request.type());}public synchronized DamageResult apply(DamageRequest request){DamageResult result=calculate(request);health.compute(request.target(),(id,current)->Math.max(0,Objects.requireNonNullElse(current,0d)-result.amount()));return result;}public double health(UUID entity){return health.getOrDefault(entity,0d);}}
